INSERT [dbo].[Scripts] ([Id], [Topic], [RawJson], [CreatedAt], [GapReportId], [User_Id]) VALUES (2041, N'أفضل النصائح للبرمجة', N'{"video_type":"youtube_long","description_data":{"video_description":"\u0647\u0644 \u062A\u0637\u0645\u062D \u0644\u062A\u0635\u0628\u062D \u0645\u0628\u0631\u0645\u062C\u0627\u064B \u0627\u0633\u062A\u062B\u0646\u0627\u0626\u064A\u0627\u064B\u061F \u0641\u064A \u0647\u0630\u0627 \u0627\u0644\u0641\u064A\u062F\u064A\u0648\u060C \u0646\u0642\u062F\u0645 \u0644\u0643 \u0623\u0641\u0636\u0644 \u0627\u0644\u0646\u0635\u0627\u0626\u062D \u0644\u0644\u0628\u0631\u0645\u062C\u0629 \u0627\u0644\u062A\u064A \u0633\u062A\u0646\u0642\u0644 \u0645\u0647\u0627\u0631\u0627\u062A\u0643 \u0625\u0644\u0649 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 \u0627\u0644\u062A\u0627\u0644\u064A! \u0645\u0646 \u0641\u0647\u0645 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A \u0628\u0639\u0645\u0642 \u0625\u0644\u0649 \u0625\u062A\u0642\u0627\u0646 \u0641\u0646 \u062A\u062A\u0628\u0639 \u0627\u0644\u0623\u062E\u0637\u0627\u0621 \u0648\u0627\u0644\u062A\u0639\u0644\u0645 \u0627\u0644\u0645\u0633\u062A\u0645\u0631\u060C \u0633\u064A\u0643\u0634\u0641 \u0647\u0630\u0627 \u0627\u0644\u062F\u0644\u064A\u0644 \u0627\u0644\u0634\u0627\u0645\u0644 \u0639\u0646 \u0623\u0633\u0631\u0627\u0631 \u0643\u062A\u0627\u0628\u0629 \u0643\u0648\u062F \u0646\u0638\u064A\u0641\u060C \u0641\u0639\u0627\u0644\u060C \u0648\u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u0648\u0633\u0639. \u0644\u0627 \u062A\u0643\u062A\u0641\u0650 \u0628\u0643\u062A\u0627\u0628\u0629 \u0627\u0644\u0623\u0643\u0648\u0627\u062F\u060C \u0628\u0644 \u0627\u062A\u0642\u0646 \u0641\u0646 \u0627\u0644\u0628\u0631\u0645\u062C\u0629. \u0634\u0627\u0647\u062F \u0627\u0644\u0622\u0646 \u0644\u062A\u0643\u062A\u0634\u0641 \u0643\u064A\u0641 \u064A\u0645\u0643\u0646\u0643 \u062A\u0633\u0631\u064A\u0639 \u0645\u0633\u064A\u0631\u062A\u0643 \u0627\u0644\u062A\u0639\u0644\u064A\u0645\u064A\u0629 \u0648\u062A\u0635\u0628\u062D \u0645\u0628\u0631\u0645\u062C\u0627\u064B \u0645\u062D\u062A\u0631\u0641\u0627\u064B \u0648\u0645\u0637\u0644\u0648\u0628\u0627\u064B \u0641\u064A \u0633\u0648\u0642 \u0627\u0644\u0639\u0645\u0644 \u0627\u0644\u0645\u062A\u063A\u064A\u0631 \u0628\u0627\u0633\u062A\u0645\u0631\u0627\u0631. #\u0628\u0631\u0645\u062C\u0629 #\u0646\u0635\u0627\u0626\u062D_\u0628\u0631\u0645\u062C\u0629 #\u062A\u0639\u0644\u0645_\u0627\u0644\u0628\u0631\u0645\u062C\u0629 #\u0645\u0628\u0631\u0645\u062C_\u0645\u062D\u062A\u0631\u0641 #\u062A\u0637\u0648\u064A\u0631_\u0645\u0647\u0627\u0631\u0627\u062A_\u0628\u0631\u0645\u062C\u064A\u0629 #\u0643\u0648\u062F_\u0646\u0638\u064A\u0641 #\u0623\u0633\u0627\u0633\u064A\u0627\u062A_\u0627\u0644\u0628\u0631\u0645\u062C\u0629 #Debugging","top_5_hook_sentences":["\u062A\u0648\u0642\u0641 \u0639\u0646 \u0627\u0644\u0648\u0642\u0648\u0639 \u0641\u064A \u0641\u062E \u0627\u0644\u0623\u062E\u0637\u0627\u0621 \u0627\u0644\u0628\u0631\u0645\u062C\u064A\u0629 \u0627\u0644\u0645\u062A\u0643\u0631\u0631\u0629! \u0647\u0630\u0627 \u0627\u0644\u0641\u064A\u062F\u064A\u0648 \u0647\u0648 \u0627\u0644\u062D\u0644.","\u0647\u0644 \u062A\u0631\u064A\u062F \u0623\u0646 \u062A\u0635\u0628\u062D \u0645\u0628\u0631\u0645\u062C\u0627\u064B \u0627\u0633\u062A\u062B\u0646\u0627\u0626\u064A\u0627\u064B\u061F \u0647\u0630\u0647 \u0627\u0644\u0646\u0635\u0627\u0626\u062D \u0627\u0644\u0630\u0647\u0628\u064A\u0629 \u0633\u062A\u063A\u064A\u0631 \u0645\u0633\u064A\u0631\u062A\u0643!","\u0627\u0643\u062A\u0634\u0641 \u0627\u0644\u0623\u0633\u0631\u0627\u0631 \u0627\u0644\u062E\u0641\u064A\u0629 \u0644\u0643\u062A\u0627\u0628\u0629 \u0643\u0648\u062F \u0646\u0638\u064A\u0641 \u0648\u0641\u0639\u0627\u0644 \u064A\u0630\u0647\u0644 \u0627\u0644\u062C\u0645\u064A\u0639.","5 \u062F\u0642\u0627\u0626\u0642 \u0641\u0642\u0637 \u0644\u062A\u062A\u0639\u0644\u0645 \u0643\u064A\u0641 \u062A\u0633\u0631\u0639 \u0639\u0645\u0644\u064A\u0629 \u062A\u0639\u0644\u0645\u0643 \u0648\u062A\u062A\u0642\u0646 \u0641\u0646 \u0627\u0644\u0628\u0631\u0645\u062C\u0629.","\u0644\u0627 \u062A\u0643\u062A\u0628 \u0627\u0644\u0643\u0648\u062F \u0641\u0642\u0637\u060C \u0628\u0644 \u0627\u062A\u0642\u0646 \u0627\u0644\u0628\u0631\u0645\u062C\u0629! \u062F\u0644\u064A\u0644\u0643 \u0627\u0644\u0634\u0627\u0645\u0644 \u0647\u0646\u0627."]},"hook_and_intro":{"title":"","presenter_speech":"\u0645\u0631\u062D\u0628\u0627\u064B \u0628\u0643\u0645 \u0623\u064A\u0647\u0627 \u0627\u0644\u0645\u0628\u0631\u0645\u062C\u0648\u0646 \u0627\u0644\u0637\u0645\u0648\u062D\u0648\u0646 \u0648\u0627\u0644\u0645\u062D\u062A\u0631\u0641\u0648\u0646! \u0647\u0644 \u062A\u0634\u0639\u0631\u0648\u0646 \u0623\u062D\u064A\u0627\u0646\u0627\u064B \u0628\u0623\u0646\u0643\u0645 \u0639\u0627\u0644\u0642\u0648\u0646 \u0641\u064A \u062D\u0644\u0642\u0629 \u0645\u0641\u0631\u063A\u0629 \u0645\u0646 \u0627\u0644\u0623\u062E\u0637\u0627\u0621\u060C \u0623\u0648 \u0623\u0646 \u0643\u0648\u062F\u0643\u0645 \u0644\u0627 \u064A\u0631\u062A\u0642\u064A \u0644\u0644\u0645\u0633\u062A\u0648\u0649 \u0627\u0644\u0630\u064A \u062A\u0637\u0645\u062D\u0648\u0646 \u0625\u0644\u064A\u0647\u061F \u0641\u064A \u0639\u0627\u0644\u0645 \u064A\u062A\u0637\u0648\u0631 \u0628\u0633\u0631\u0639\u0629 \u0627\u0644\u0628\u0631\u0642\u060C \u0644\u0645 \u064A\u0639\u062F \u0643\u0627\u0641\u064A\u0627\u064B \u0645\u062C\u0631\u062F \u0643\u062A\u0627\u0628\u0629 \u0627\u0644\u0623\u0643\u0648\u0627\u062F\u061B \u0628\u0644 \u064A\u062C\u0628 \u0623\u0646 \u0646\u062A\u0642\u0646 \u0641\u0646 \u0627\u0644\u0628\u0631\u0645\u062C\u0629. \u0641\u064A \u0647\u0630\u0627 \u0627\u0644\u0641\u064A\u062F\u064A\u0648\u060C \u0633\u0623\u0634\u0627\u0631\u0643\u0643\u0645 \u062E\u0644\u0627\u0635\u0629 \u062A\u062C\u0631\u0628\u062A\u064A \u0648\u0623\u0642\u062F\u0645 \u0644\u0643\u0645 \u0623\u0641\u0636\u0644 \u0627\u0644\u0646\u0635\u0627\u0626\u062D \u0627\u0644\u0630\u0647\u0628\u064A\u0629 \u0627\u0644\u062A\u064A \u0633\u062A\u0633\u0627\u0639\u062F\u0643\u0645 \u0639\u0644\u0649 \u0628\u0646\u0627\u0621 \u0623\u0633\u0627\u0633 \u0645\u062A\u064A\u0646\u060C \u0648\u062A\u062D\u0633\u064A\u0646 \u062C\u0648\u062F\u0629 \u0643\u0648\u062F\u0643\u0645\u060C \u0644\u062A\u0635\u0628\u062D\u0648\u0627 \u0645\u0628\u0631\u0645\u062C\u064A\u0646 \u0627\u0633\u062A\u062B\u0646\u0627\u0626\u064A\u064A\u0646. \u0627\u0633\u062A\u0639\u062F\u0648\u0627 \u0644\u0631\u062D\u0644\u0629 \u0633\u062A\u063A\u064A\u0631 \u0646\u0638\u0631\u062A\u0643\u0645 \u0644\u0644\u0628\u0631\u0645\u062C\u0629!","actions_and_visuals":"\u064A\u0628\u062F\u0623 \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u0628\u0627\u0644\u0646\u0638\u0631 \u0645\u0628\u0627\u0634\u0631\u0629 \u0625\u0644\u0649 \u0627\u0644\u0643\u0627\u0645\u064A\u0631\u0627 \u0628\u0627\u0628\u062A\u0633\u0627\u0645\u0629 \u0648\u0627\u062B\u0642\u0629\u060C \u062B\u0645 \u064A\u062A\u062E\u0630 \u0648\u0636\u0639\u064A\u0629 \u062C\u0644\u0648\u0633 \u0645\u0633\u062A\u0642\u064A\u0645\u0629 \u0648\u0645\u0639\u0628\u0631\u0629. \u064A\u0633\u062A\u062E\u062F\u0645 \u0625\u064A\u0645\u0627\u0621\u0627\u062A \u064A\u062F \u0645\u0641\u062A\u0648\u062D\u0629 \u0646\u062D\u0648 \u0627\u0644\u0643\u0627\u0645\u064A\u0631\u0627 \u0644\u062C\u0630\u0628 \u0627\u0644\u0627\u0646\u062A\u0628\u0627\u0647. \u0623\u062B\u0646\u0627\u0621 \u0637\u0631\u062D \u0627\u0644\u0623\u0633\u0626\u0644\u0629\u060C \u062A\u0638\u0647\u0631 \u0646\u0635\u0648\u0635 \u062A\u0633\u0627\u0624\u0644\u064A\u0629 \u0642\u0635\u064A\u0631\u0629 \u0639\u0644\u0649 \u0627\u0644\u0634\u0627\u0634\u0629 (\u0645\u062B\u0644: \u0022\u0623\u062E\u0637\u0627\u0621 \u0645\u062A\u0643\u0631\u0631\u0629\u061F\u0022\u060C \u0022\u0643\u0648\u062F \u063A\u064A\u0631 \u0641\u0639\u0627\u0644\u061F\u0022). \u0639\u0646\u062F \u0627\u0644\u0625\u0639\u0644\u0627\u0646 \u0639\u0646 \u0645\u062D\u062A\u0648\u0649 \u0627\u0644\u0641\u064A\u062F\u064A\u0648\u060C \u062A\u062A\u0633\u0639 \u0627\u0628\u062A\u0633\u0627\u0645\u062A\u0647 \u0648\u062A\u0643\u0648\u0646 \u0646\u0628\u0631\u0629 \u0635\u0648\u062A\u0647 \u062D\u0645\u0627\u0633\u064A\u0629 \u0648\u0645\u0644\u064A\u0626\u0629 \u0628\u0627\u0644\u062B\u0642\u0629. \u062A\u0638\u0647\u0631 \u062E\u0644\u0641\u0647 \u0634\u0627\u0634\u0629 \u0639\u0631\u0636 \u0628\u0633\u064A\u0637\u0629 \u062A\u0639\u0631\u0636 \u0634\u0639\u0627\u0631 \u0627\u0644\u0642\u0646\u0627\u0629 \u0648\u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0631\u0626\u064A\u0633\u064A: \u0022\u0623\u0641\u0636\u0644 \u0627\u0644\u0646\u0635\u0627\u0626\u062D \u0644\u0644\u0628\u0631\u0645\u062C\u0629\u0022."},"main_content":[{"title":"Chapter 1: \u0641\u0647\u0645 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A \u0628\u0639\u0645\u0642","presenter_speech":"\u0646\u0628\u062F\u0623 \u0646\u0635\u064A\u062D\u062A\u0646\u0627 \u0627\u0644\u0623\u0648\u0644\u0649 \u0648\u0627\u0644\u0623\u0643\u062B\u0631 \u0623\u0647\u0645\u064A\u0629: \u0641\u0647\u0645 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A \u0628\u0639\u0645\u0642. \u0644\u0627 \u064A\u0645\u0643\u0646\u0643 \u0628\u0646\u0627\u0621 \u0646\u0627\u0637\u062D\u0629 \u0633\u062D\u0627\u0628 \u0639\u0644\u0649 \u0623\u0633\u0627\u0633 \u0647\u0634. \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u0644\u064A\u0633\u062A \u0645\u062C\u0631\u062F \u062D\u0641\u0638 \u0635\u064A\u063A \u0623\u0648 \u0645\u0643\u062A\u0628\u0627\u062A\u061B \u0625\u0646\u0647\u0627 \u0641\u0647\u0645 \u0644\u0644\u0645\u0646\u0637\u0642 \u0627\u0644\u0643\u0627\u0645\u0646 \u0648\u0631\u0627\u0621 \u0643\u0644 \u0633\u0637\u0631 \u062A\u0643\u062A\u0628\u0647. \u0631\u0643\u0632\u0648\u0627 \u0639\u0644\u0649 \u0627\u0644\u0647\u064A\u0627\u0643\u0644 \u0627\u0644\u0628\u064A\u0627\u0646\u064A\u0629 \u0645\u062B\u0644 \u0627\u0644\u0642\u0648\u0627\u0626\u0645 \u0648\u0627\u0644\u0623\u0634\u062C\u0627\u0631\u060C \u0648\u0643\u064A\u0641\u064A\u0629 \u0639\u0645\u0644 \u0627\u0644\u062E\u0648\u0627\u0631\u0632\u0645\u064A\u0627\u062A \u0627\u0644\u0645\u062E\u062A\u0644\u0641\u0629 \u0643\u062E\u0648\u0627\u0631\u0632\u0645\u064A\u0627\u062A \u0627\u0644\u0641\u0631\u0632 \u0648\u0627\u0644\u0628\u062D\u062B. \u0627\u0633\u062A\u0648\u0639\u0628\u0648\u0627 \u0645\u0641\u0627\u0647\u064A\u0645 \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u0627\u0644\u0643\u0627\u0626\u0646\u064A\u0629 \u0627\u0644\u062A\u0648\u062C\u0647 \u0623\u0648 \u0627\u0644\u0648\u0638\u064A\u0641\u064A\u0629. \u0647\u0630\u0647 \u0627\u0644\u0645\u0641\u0627\u0647\u064A\u0645 \u0647\u064A \u0627\u0644\u0644\u0628\u0646\u0627\u062A \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629 \u0644\u0623\u064A \u0646\u0638\u0627\u0645 \u0628\u0631\u0645\u062C\u064A \u0645\u0639\u0642\u062F. \u0639\u0646\u062F\u0645\u0627 \u062A\u0641\u0647\u0645\u0648\u0646 \u0647\u0630\u0647 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A \u062D\u0642\u0627\u064B\u060C \u0633\u062A\u062A\u0645\u0643\u0646\u0648\u0646 \u0645\u0646 \u062D\u0644 \u0627\u0644\u0645\u0634\u0643\u0644\u0627\u062A \u0628\u0643\u0641\u0627\u0621\u0629 \u0623\u0643\u0628\u0631\u060C \u0648\u0643\u062A\u0627\u0628\u0629 \u0643\u0648\u062F \u0646\u0638\u064A\u0641 \u0648\u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u0648\u0633\u0639\u060C \u0628\u063A\u0636 \u0627\u0644\u0646\u0638\u0631 \u0639\u0646 \u0627\u0644\u0644\u063A\u0629 \u0623\u0648 \u0627\u0644\u0625\u0637\u0627\u0631. \u0644\u0627 \u062A\u0633\u062A\u0639\u062C\u0644\u0648\u0627 \u0647\u0630\u0647 \u0627\u0644\u0645\u0631\u062D\u0644\u0629\u060C \u0641\u0627\u0633\u062A\u062B\u0645\u0627\u0631\u0643\u0645 \u0641\u064A\u0647\u0627 \u0633\u064A\u0624\u062A\u064A \u062B\u0645\u0627\u0631\u0647 \u0623\u0636\u0639\u0627\u0641\u0627\u064B \u0645\u0636\u0627\u0639\u0641\u0629.","actions_and_visuals":"\u064A\u064F\u0634\u064A\u0631 \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u0628\u0625\u0635\u0628\u0639\u0647 \u0646\u062D\u0648 \u0627\u0644\u0623\u0639\u0644\u0649 \u0644\u0644\u062A\u0623\u0643\u064A\u062F \u0639\u0644\u0649 \u0623\u0647\u0645\u064A\u0629 \u0627\u0644\u0646\u0642\u0637\u0629 \u0627\u0644\u0623\u0648\u0644\u0649. \u062A\u0638\u0647\u0631 \u0639\u0644\u0649 \u0627\u0644\u0634\u0627\u0634\u0629 \u0631\u0633\u0648\u0645 \u0628\u064A\u0627\u0646\u064A\u0629 \u0645\u062A\u062D\u0631\u0643\u0629 \u0628\u0633\u064A\u0637\u0629 \u062A\u0648\u0636\u062D \u0627\u0644\u0647\u064A\u0627\u0643\u0644 \u0627\u0644\u0628\u064A\u0627\u0646\u064A\u0629 (\u0645\u062B\u0644 \u0631\u0633\u0645 \u0634\u062C\u0631\u0629 \u0628\u064A\u0627\u0646\u0627\u062A \u0623\u0648 \u0642\u0627\u0626\u0645\u0629 \u0645\u062A\u0635\u0644\u0629). \u062B\u0645 \u062A\u062A\u062D\u0648\u0644 \u0627\u0644\u0634\u0627\u0634\u0629 \u0644\u0639\u0631\u0636 \u0623\u0645\u062B\u0644\u0629 \u0643\u0648\u062F \u0642\u0635\u064A\u0631\u0629 \u062C\u062F\u0627\u064B (B-roll) \u062A\u0648\u0636\u062D \u062E\u0648\u0627\u0631\u0632\u0645\u064A\u0629 \u0641\u0631\u0632 \u0628\u0633\u064A\u0637\u0629 \u0623\u0648 \u0647\u064A\u0643\u0644 \u0643\u0644\u0627\u0633 \u0641\u064A \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u0627\u0644\u0643\u0627\u0626\u0646\u064A\u0629\u060C \u0645\u0639 \u0627\u0644\u062A\u0631\u0643\u064A\u0632 \u0627\u0644\u0628\u0635\u0631\u064A \u0639\u0644\u0649 \u0627\u0644\u0623\u062C\u0632\u0627\u0621 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629. \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u064A\u062D\u0627\u0641\u0638 \u0639\u0644\u0649 \u0627\u062A\u0635\u0627\u0644 \u0628\u0635\u0631\u064A \u0642\u0648\u064A \u0648\u064A\u0648\u0645\u0626 \u0628\u0631\u0623\u0633\u0647 \u0644\u0644\u062A\u0623\u0643\u064A\u062F."},{"title":"Chapter 2: \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0629 \u0627\u0644\u0645\u0633\u062A\u0645\u0631\u0629 \u0648\u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u0635\u063A\u064A\u0631\u0629","presenter_speech":"\u0627\u0644\u0646\u0635\u064A\u062D\u0629 \u0627\u0644\u062B\u0627\u0646\u064A\u0629 \u0647\u064A \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0629 \u0627\u0644\u0645\u0633\u062A\u0645\u0631\u0629 \u0648\u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0627\u0644\u0635\u063A\u064A\u0631\u0629. \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u0645\u0647\u0627\u0631\u0629 \u0639\u0645\u0644\u064A\u0629 \u0628\u062D\u062A\u0629\u060C \u0648\u0644\u0627 \u064A\u0645\u0643\u0646 \u0625\u062A\u0642\u0627\u0646\u0647\u0627 \u0628\u0645\u062C\u0631\u062F \u0627\u0644\u0642\u0631\u0627\u0621\u0629 \u0623\u0648 \u0627\u0644\u0645\u0634\u0627\u0647\u062F\u0629. \u062E\u0635\u0635\u0648\u0627 \u0648\u0642\u062A\u0627\u064B \u064A\u0648\u0645\u064A\u0627\u064B \u0644\u0644\u0628\u0631\u0645\u062C\u0629\u060C \u062D\u062A\u0649 \u0644\u0648 \u0643\u0627\u0646\u062A \u0644\u0645\u0634\u0643\u0644\u0629 \u0635\u063A\u064A\u0631\u0629 \u0639\u0644\u0649 \u0645\u0646\u0635\u0627\u062A \u0645\u062B\u0644 LeetCode \u0623\u0648 HackerRank. \u0627\u0644\u0623\u0647\u0645 \u0645\u0646 \u0630\u0644\u0643\u060C \u0627\u0628\u062F\u0623\u0648\u0627 \u0641\u064A \u0628\u0646\u0627\u0621 \u0645\u0634\u0627\u0631\u064A\u0639\u0643\u0645 \u0627\u0644\u062E\u0627\u0635\u0629\u060C \u0645\u0647\u0645\u0627 \u0643\u0627\u0646\u062A \u0628\u0633\u064A\u0637\u0629 \u0641\u064A \u0627\u0644\u0628\u062F\u0627\u064A\u0629. \u0645\u0634\u0631\u0648\u0639 \u062D\u0627\u0633\u0628\u0629 \u0628\u0633\u064A\u0637\u060C \u0623\u0648 \u062A\u0637\u0628\u064A\u0642 \u0642\u0627\u0626\u0645\u0629 \u0645\u0647\u0627\u0645\u060C \u0623\u0648 \u062D\u062A\u0649 \u0645\u0648\u0642\u0639 \u0648\u064A\u0628 \u0634\u062E\u0635\u064A. \u0647\u0630\u0647 \u0627\u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u062A\u0633\u0645\u062D \u0644\u0643\u0645 \u0628\u062A\u0637\u0628\u064A\u0642 \u0627\u0644\u0645\u0639\u0631\u0641\u0629 \u0627\u0644\u0646\u0638\u0631\u064A\u0629\u060C \u0648\u0645\u0648\u0627\u062C\u0647\u0629 \u0627\u0644\u0645\u0634\u0643\u0644\u0627\u062A \u0627\u0644\u062D\u0642\u064A\u0642\u064A\u0629\u060C \u0648\u062A\u0639\u0644\u0645 \u0643\u064A\u0641\u064A\u0629 \u0627\u0644\u0628\u062D\u062B \u0639\u0646 \u0627\u0644\u062D\u0644\u0648\u0644. \u0644\u0627 \u062A\u062E\u0634\u0648\u0627 \u0627\u0644\u0641\u0634\u0644\u061B \u0643\u0644 \u062E\u0637\u0623 \u0647\u0648 \u0641\u0631\u0635\u0629 \u0644\u0644\u062A\u0639\u0644\u0645. \u062A\u0630\u0643\u0631\u0648\u0627\u060C \u0623\u0641\u0636\u0644 \u0637\u0631\u064A\u0642\u0629 \u0644\u062A\u0639\u0644\u0645 \u0627\u0644\u0633\u0628\u0627\u062D\u0629 \u0647\u064A \u0628\u0627\u0644\u0646\u0632\u0648\u0644 \u0625\u0644\u0649 \u0627\u0644\u0645\u0627\u0621\u060C \u0648\u0644\u064A\u0633 \u0628\u0642\u0631\u0627\u0621\u0629 \u0643\u062A\u0628 \u0639\u0646 \u0627\u0644\u0633\u0628\u0627\u062D\u0629.","actions_and_visuals":"\u064A\u064F\u062D\u0631\u0643 \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u064A\u062F\u064A\u0647 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0631\u064A \u0643\u0625\u0634\u0627\u0631\u0629 \u0625\u0644\u0649 \u0627\u0644\u0627\u0633\u062A\u0645\u0631\u0627\u0631\u064A\u0629. \u062A\u0638\u0647\u0631 \u0639\u0644\u0649 \u0627\u0644\u0634\u0627\u0634\u0629 \u0644\u0642\u0637\u0627\u062A B-roll \u0633\u0631\u064A\u0639\u0629 \u0644\u0634\u062E\u0635 \u064A\u0628\u0631\u0645\u062C \u0628\u062A\u0631\u0643\u064A\u0632 \u0639\u0644\u0649 \u0634\u0627\u0634\u0629 \u0639\u0631\u0636 \u0645\u062A\u0639\u062F\u062F\u0629\u060C \u062B\u0645 \u0644\u0642\u0637\u0627\u062A \u0644\u0634\u0627\u0634\u0627\u062A \u062A\u0639\u0631\u0636 \u0648\u0627\u062C\u0647\u0627\u062A \u0645\u0633\u062A\u062E\u062F\u0645 \u0644\u0645\u0634\u0627\u0631\u064A\u0639 \u0628\u0633\u064A\u0637\u0629 (\u0645\u062B\u0644 \u062A\u0637\u0628\u064A\u0642 \u0645\u0647\u0627\u0645 \u0645\u0643\u062A\u0645\u0644). \u064A\u0645\u0643\u0646 \u0639\u0631\u0636 \u0644\u0642\u0637\u0627\u062A \u0634\u0627\u0634\u0629 \u0642\u0635\u064A\u0631\u0629 \u0644\u0645\u0646\u0635\u0627\u062A \u062D\u0644 \u0627\u0644\u0645\u0634\u0643\u0644\u0627\u062A \u0627\u0644\u0628\u0631\u0645\u062C\u064A\u0629. \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u064A\u0645\u064A\u0644 \u0642\u0644\u064A\u0644\u0627\u064B \u0646\u062D\u0648 \u0627\u0644\u0643\u0627\u0645\u064A\u0631\u0627 \u0643\u0623\u0646\u0647 \u064A\u0634\u0627\u0631\u0643 \u0633\u0631\u0627\u064B\u060C \u062B\u0645 \u064A\u0628\u062A\u0633\u0645 \u0639\u0646\u062F \u0630\u0643\u0631 \u0645\u062B\u0627\u0644 \u0627\u0644\u0633\u0628\u0627\u062D\u0629."},{"title":"Chapter 3: \u062A\u0639\u0644\u0645 \u0627\u0644\u0642\u0631\u0627\u0621\u0629 \u0648\u0627\u0644\u062A\u062A\u0628\u0639 (Debugging)","presenter_speech":"\u0646\u0646\u062A\u0642\u0644 \u0625\u0644\u0649 \u0627\u0644\u0646\u0635\u064A\u062D\u0629 \u0627\u0644\u062B\u0627\u0644\u062B\u0629: \u0625\u062A\u0642\u0627\u0646 \u0641\u0646 \u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0643\u0648\u062F \u0648\u062A\u062A\u0628\u0639 \u0627\u0644\u0623\u062E\u0637\u0627\u0621. \u0627\u0644\u0645\u0628\u0631\u0645\u062C \u0644\u0627 \u064A\u0643\u062A\u0628 \u0627\u0644\u0643\u0648\u062F \u0641\u0642\u0637\u061B \u0628\u0644 \u064A\u0642\u0636\u064A \u0648\u0642\u062A\u0627\u064B \u0637\u0648\u064A\u0644\u0627\u064B \u0641\u064A \u0642\u0631\u0627\u0621\u0629 \u0648\u0641\u0647\u0645 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0643\u062A\u0648\u0628 \u0628\u0627\u0644\u0641\u0639\u0644\u060C \u0633\u0648\u0627\u0621 \u0643\u0627\u0646 \u0643\u0648\u062F\u0647 \u0627\u0644\u062E\u0627\u0635 \u0623\u0648 \u0643\u0648\u062F \u0627\u0644\u0622\u062E\u0631\u064A\u0646. \u062A\u0639\u0644\u0645\u0648\u0627 \u0643\u064A\u0641\u064A\u0629 \u062A\u062D\u0644\u064A\u0644 \u0627\u0644\u0643\u0648\u062F\u060C \u0641\u0647\u0645 \u062A\u062F\u0641\u0642\u0647\u060C \u0648\u062A\u062D\u062F\u064A\u062F \u0627\u0644\u0623\u0645\u0627\u0643\u0646 \u0627\u0644\u0645\u062D\u062A\u0645\u0644\u0629 \u0644\u0644\u0645\u0634\u0643\u0644\u0627\u062A. \u0648\u0627\u0644\u0623\u0647\u0645 \u0645\u0646 \u0630\u0644\u0643\u060C \u0627\u0633\u062A\u062B\u0645\u0631\u0648\u0627 \u0627\u0644\u0648\u0642\u062A \u0641\u064A \u062A\u0639\u0644\u0645 \u0623\u062F\u0648\u0627\u062A \u0627\u0644\u062A\u062A\u0628\u0639 (Debuggers) \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0644\u063A\u062A\u0643\u0645 \u0627\u0644\u0645\u0641\u0636\u0644\u0629. \u0627\u0644\u0642\u062F\u0631\u0629 \u0639\u0644\u0649 \u062A\u062A\u0628\u0639 \u062A\u0646\u0641\u064A\u0630 \u0627\u0644\u0643\u0648\u062F \u062E\u0637\u0648\u0629 \u0628\u062E\u0637\u0648\u0629\u060C \u0648\u0641\u062D\u0635 \u0642\u064A\u0645 \u0627\u0644\u0645\u062A\u063A\u064A\u0631\u0627\u062A \u0641\u064A \u0643\u0644 \u0645\u0631\u062D\u0644\u0629\u060C \u0647\u064A \u0645\u0647\u0627\u0631\u0629 \u0644\u0627 \u062A\u0642\u062F\u0631 \u0628\u062B\u0645\u0646. \u0625\u0646\u0647\u0627 \u062A\u0633\u0631\u0639 \u0639\u0645\u0644\u064A\u0629 \u0627\u0643\u062A\u0634\u0627\u0641 \u0627\u0644\u0623\u062E\u0637\u0627\u0621 \u0648\u0625\u0635\u0644\u0627\u062D\u0647\u0627 \u0628\u0634\u0643\u0644 \u0643\u0628\u064A\u0631\u060C \u0648\u062A\u0648\u0641\u0631 \u0639\u0644\u064A\u0643\u0645 \u0633\u0627\u0639\u0627\u062A \u0644\u0627 \u062A\u062D\u0635\u0649 \u0645\u0646 \u0627\u0644\u0625\u062D\u0628\u0627\u0637. \u0627\u0639\u062A\u0628\u0631\u0648\u0627 \u0627\u0644\u0640 Debugger \u0635\u062F\u064A\u0642\u0643\u0645 \u0627\u0644\u0645\u062E\u0644\u0635 \u0641\u064A \u0631\u062D\u0644\u0629 \u0627\u0644\u0628\u0631\u0645\u062C\u0629.","actions_and_visuals":"\u064A\u064F\u0638\u0647\u0631 \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u062A\u0639\u0627\u0628\u064A\u0631 \u0648\u062C\u0647 \u062C\u0627\u062F\u0629 \u0648\u0645\u0641\u0643\u0631\u0629. \u062A\u0638\u0647\u0631 \u0639\u0644\u0649 \u0627\u0644\u0634\u0627\u0634\u0629 \u0644\u0642\u0637\u0627\u062A B-roll \u0644\u0634\u0627\u0634\u0629 \u0639\u0631\u0636 \u062A\u0639\u0631\u0636 \u0645\u062D\u0631\u0631 \u0623\u0643\u0648\u0627\u062F \u0645\u0639 \u062A\u0633\u0644\u064A\u0637 \u0627\u0644\u0636\u0648\u0621 \u0639\u0644\u0649 \u0623\u062C\u0632\u0627\u0621 \u0645\u0639\u064A\u0646\u0629 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F (\u0643\u0623\u0646\u0645\u0627 \u064A\u062A\u0645 \u0642\u0631\u0627\u0621\u062A\u0647\u0627). \u062B\u0645 \u062A\u062A\u062D\u0648\u0644 \u0625\u0644\u0649 \u0644\u0642\u0637\u0627\u062A \u0634\u0627\u0634\u0629 \u0644\u0623\u062F\u0627\u0629 Debugger \u0648\u0647\u064A \u062A\u0639\u0645\u0644\u060C \u062A\u064F\u0638\u0647\u0631 \u0646\u0642\u0627\u0637 \u0627\u0644\u062A\u0648\u0642\u0641 (breakpoints) \u0648\u062A\u062A\u0628\u0639 \u0627\u0644\u0645\u062A\u063A\u064A\u0631\u0627\u062A. \u064A\u0645\u0643\u0646 \u0639\u0631\u0636 \u0623\u064A\u0642\u0648\u0646\u0627\u062A \u0644\u0623\u062F\u0648\u0627\u062A Debugger \u0634\u0647\u064A\u0631\u0629. \u0627\u0644\u064A\u0648\u062A\u064A\u0648\u0628\u0631 \u064A\u0636\u0639 \u0625\u0635\u0628\u0639\u0647 \u0639\u0644\u0649 \u0630\u0642\u0646\u0647 \u0643\u0639\u0644\u0627\u0645\u0629 \u0639\u0644\u0649 \u0627\u0644\u062A\u0641\u0643\u064A\u0631 \u0627\u0644\u0639\u0645\u064A\u0642 \u062B\u0645 \u064A\u0648\u0645\u0626 \u0628\u0631\u0623\u0633\u0647 \u0645\u0648\u0627\u0641\u0642\u0627\u064B."},{"title":"Chapter 4: \u0627\u0644\u0628\u0642\u0627\u0621 \u0639\u0644\u0649 \u0627\u0637\u0644\u0627\u0639 \u0648\u0627\u0644\u062A\u0639\u0644\u0645 \u0627\u0644\u0645\u0633\u062A\u0645\u0631","presenter_speech":"\u0623\u062E\u064A\u0631\u0627\u064B\u060C \u0646\u0635\u064A\u062D\u062A\u0646\u0627 \u0627\u0644\u0631\u0627\u0628\u0639\u0629 \u0648\u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629: \u0627\u0644\u0628\u0642\u0627\u0621 \u0639\u0644\u0649 \u0627\u0637\u0644\u0627\u0639 \u0648\u0627\u0644\u062A\u0639\u0644\u0645 \u0627\u0644\u0645\u0633\u062A\u0645\u0631. \u0639\u0627\u0644\u0645 \u0627\u0644\u0628\u0631\u0645\u062C\u0629 \u064A\u062A\u063A\u064A\u0631 \u0628\u0648\u062A\u064A\u0631\u0629 \u0645\u0630\u0647\u0644\u0629. \u0645\u0627 \u0643\u0627\u0646 \u0645\u062A\u0637\u0648\u0631\u0627\u064B \u0627\u0644\u064A\u0648\u0645 \u0642\u062F \u064A\u0635\u0628\u062D \u0642\u062F\u064A\u0645\u0627\u064B \u063A\u062F\u0627\u064B. \u0644\u0630\u0644\u0643\u060C \u064A\u062C\u0628 \u0623\u0646 \u062A\u062A\u0628\u0646\u0648\u0627 \u0639\u0642\u0644\u064A\u0629 \u0627\u0644\u062A\u0639\u0644\u0645 \u0645\u062F\u0649 \u0627\u0644\u062D\u064A\u0627\u0629. \u062A\u0627\u0628\u0639\u0648\u0627 \u0627\u0644\u0645\u062F\u0648\u0646\u0627\u062A \u0627\u0644\u062A\u0642\u0646\u064A\u0629\u060C \u0627\u0634\u062A\u0631\u0643\u0648\u0627 \u0641\u064A \u0627\u0644\u0646\u0634\u0631\u0627\u062A \u0627\u0644\u0625\u062E\u0628\u0627\u0631\u064A\u0629 \u0644\u0644\u0645\u0637\u0648\u0631\u064A\u0646\u060C \u0648\u0634\u0627\u0631\u0643\u0648\u0627 \u0641\u064A \u0627\u0644\u0645\u062C\u062A\u0645\u0639\u0627\u062A \u0627\u0644\u0628\u0631\u0645\u062C\u064A\u0629. \u0644\u0627 \u062A\u062E\u0627\u0641\u0648\u0627 \u0645\u0646 \u0627\u0633\u062A\u0643\u0634\u0627\u0641 \u0644\u063A\u0627\u062A \u062C\u062F\u064A\u062F\u0629\u060C \u0623\u0637\u0631 \u0639\u0645\u0644 \u0645\u062E\u062A\u0644\u0641\u0629\u060C \u0623\u0648 \u062D\u062A\u0649 \u0645\u0641\u0627\u0647\u064A\u0645 \u0628\u0631\u0645\u062C\u064A\u0629 \u062C\u062F\u064A\u062F\u0629. \u0647\u0630\u0627 \u0644\u0627 \u064A\u0639\u0646\u064A \u0627\u0644\u0642\u0641\u0632 \u0645\u0646 \u062A\u0642\u0646\u064A\u0629 \u0644\u0623\u062E\u0631\u0649 \u0628\u0627\u0633\u062A\u0645\u0631\u0627\u0631\u060C \u0628\u0644 \u064A\u0639\u0646\u064A \u0627\u0645\u062A\u0644\u0627\u0643 \u0627\u0644\u0641\u0636\u0648\u0644 \u0648\u0627\u0644\u0631\u063A\u0628\u0629 \u0641\u064A \u0627\u0644\u062A\u0648\u0633\u0639 \u0627\u0644\u0645\u0639\u0631\u0641\u064A. \u0627\u0644\u062A\u0639\u0644\u0645 \u0627\u0644\u0645\u0633\u062A\u0645\u0631 \u0633\u064A\u062D\u0627\u0641\u0638 \u0639\u0644\u0649 \u0645\u0647\u0627\u0631\u0627\u062