ech":"\u0648\u0647\u0643\u0630\u0627 \u0646\u0635\u0644 \u0625\u0644\u0649 \u062E\u062A\u0627\u0645 \u0631\u062D\u0644\u062A\u0646\u0627 \u0641\u064A \u0639\u0627\u0644\u0645 \u0623\u0641\u0636\u0644 \u0646\u0635\u0627\u0626\u062D \u0627\u0644\u0628\u0631\u0645\u062C\u0629. \u062A\u0630\u0643\u0631\u0648\u0627\u060C \u0641\u0647\u0645 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0627\u062A\u060C \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0629 \u0627\u0644\u0645\u0633\u062A\u0645\u0631\u0629\u060C \u0625\u062A\u0642\u0627\u0646 \u0642\u0631\u0627\u0621\u0629 \u0648\u062A\u062A\u0628\u0639 \u0627\u0644\u0643\u0648\u062F\u060C \u0648\u0627\u0644\u0628\u0642\u0627\u0621 \u0639\u0644\u0649 \u0627\u0637\u0644\u0627\u0639 \u062F\u0627\u0626\u0645\u060C \u0647\u064A \u0631\u0643\u0627\u0626\u0632 \u0623\u0633\u0627\u0633\u064A\u0629 \u0644\u0646\u0645\u0648\u0643\u0645 \u0643\u0645\u0628\u0631\u0645\u062C\u064A\u0646. \u0637\u0628\u0642\u0648\u0627 \u0647\u0630\u0647 \u0627\u0644\u0646\u0635\u0627\u0626\u062D \u0628\u062C\u062F\u064A\u0629\u060C \u0648\u0633\u062A\u0631\u0648\u0646 \u0641\u0631\u0642\u0627\u064B \u0647\u0627\u0626\u0644\u0627\u064B \u0641\u064A \u062C\u0648\u062F\u0629 \u0639\u0645\u0644\u0643\u0645 \u0648\u0633\u0631\u0639\u0629 \u062A\u0639\u0644\u0645\u0643\u0645. \u0625\u0630\u0627 \u0648\u062C\u062F\u062A\u0645 \u0647\u0630\u0627 \u0627\u0644\u0641\u064A\u062F\u064A\u0648 \u0645\u0641\u064A\u062F\u0627\u064B\u060C \u0641\u0644\u0627 \u062A\u0646\u0633\u0648\u0627 \u0627\u0644\u0636\u063A\u0637 \u0639\u0644\u0649 \u0632\u0631 \u0627\u0644\u0625\u0639\u062C\u0627\u0628 \u0648\u0627\u0644\u0627\u0634\u062A\u0631\u0627\u0643 \u0641\u064A \u0627\u0644\u0642\u0646\u0627\u0629. \u0634\u0627\u0631\u0643\u0648\u0646\u064A \u0641\u064A \u0627\u0644\u062A\u0639\u0644\u064A\u0642\u0627\u062A \u0623\u062F\u0646\u0627\u0647: \u0645\u0627 \u0647\u064A \u0627\u0644\u0646\u0635\u064A\u062D\u0629 \u0627\u0644\u062A\u064A \u0648\u062C\u062F\u062A\u0645\u0648\u0647\u0627 